#[cfg(test)]
mod tests {
    use super::*;
    use std::thread;

    #[test]
    fn concurrent_inventory_updates() {
        let mut initial = HashMap::new();
        initial.insert("widget".to_string(), 100);

        let inventory = create_inventory(initial);

        let mut handles = Vec::new();
        for _ in 0..10 {
            let inv = Arc::clone(&inventory);
            handles.push(thread::spawn(move || {
                for _ in 0..5 {
                    inv.check_and_decrement("widget", 2).unwrap();
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        assert_eq!(inventory.get_stock("widget"), Some(0));
    }

    #[test]
    fn insufficient_stock_is_handled() {
        let mut initial = HashMap::new();
        initial.insert("item".to_string(), 3);

        let inventory = create_inventory(initial);

        let a = {
            let inv = Arc::clone(&inventory);
            thread::spawn(move || inv.check_and_decrement("item", 2))
        };

        let b = {
            let inv = Arc::clone(&inventory);
            thread::spawn(move || inv.check_and_decrement("item", 2))
        };

        let r1 = a.join().unwrap();
        let r2 = b.join().unwrap();

        let successes = [r1.is_ok(), r2.is_ok()].into_iter().filter(|x| *x).count();
        assert_eq!(successes, 1);
        assert_eq!(inventory.get_stock("item"), Some(1));
    }
}